window.CA = {"date": "Wednesday, 01 July 2026", "updated": "2026-07-01 22:05", "updated_label": "01 Jul 2026, 22:05 IST", "items": [{"title": "VB-GRAM G (Viksit Bharat Gramin Abhiyaan Mahatma Gandhi) Replaces MGNREGA from July 1, 2026", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "The Viksit Bharat Gramin Abhiyaan Mahatma Gandhi (VB-GRAM G) scheme officially replaced the Mahatma Gandhi National Rural Employment Guarantee Act (MGNREGA) from July 1, 2026. The new scheme introduces five significant changes compared to the earlier programme, including revised state-wise wage structures. The transition marks a major overhaul of India's flagship rural employment guarantee framework.", "exam_angle": "This is a direct replacement of one of India's most significant welfare schemes (MGNREGA, enacted 2005); aspirants must know the changes introduced, the new name, and the constitutional/statutory basis of such employment guarantee programmes.", "gs_paper": "GS Paper 2 (Governance & Social Justice)", "key_facts": ["New scheme: VB-GRAM G (Viksit Bharat Gramin Abhiyaan Mahatma Gandhi)", "Replaced: MGNREGA (Mahatma Gandhi National Rural Employment Guarantee Act, 2005)", "Effective date: July 1, 2026", "Introduces 5 key changes including revised state-wise wage rates"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Commercial LPG Cylinder Prices Cut by Rs 183.50 from July 1, 2026", "category": "economy", "category_name": "Economy & Banking", "summary": "The government slashed commercial LPG cylinder prices by Rs 183.50 effective July 1, 2026. This is a significant reduction affecting hotels, restaurants, and commercial establishments across India. The price revision is linked to easing global oil prices and is separate from domestic cooking gas cylinders used in households.", "exam_angle": "LPG price revisions are linked to India's administered pricing mechanism, global crude oil trends, and the role of oil marketing companies (OMCs) under the Ministry of Petroleum; also relevant to inflation management and fuel subsidy policy.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Price cut: Rs 183.50 per commercial LPG cylinder", "Effective: July 1, 2026", "Applies to commercial (not domestic) LPG cylinders", "Driven by easing global crude oil prices"], "source": "The Indian Express / The Times of India", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Cabinet Approves Rs 14,115 Crore Road Projects Including Six-Lane Dwarka Tunnel in Delhi", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "The Union Cabinet cleared road infrastructure projects worth Rs 14,115 crore, including the construction of a six-lane Dwarka tunnel in Delhi and the Kanpur-Kabrai highway project in Uttar Pradesh. The approvals are part of the government's ongoing push to expand the national highway network. These projects are expected to ease urban traffic congestion and improve inter-city connectivity.", "exam_angle": "Cabinet approvals for infrastructure are standard UPSC current affairs; connects to Bharatmala Pariyojana, Ministry of Road Transport & Highways, and urban infrastructure planning.", "gs_paper": "GS Paper 3 (Infrastructure)", "key_facts": ["Total project cost: Rs 14,115 crore", "Key projects: Six-lane Dwarka tunnel (Delhi) and Kanpur-Kabrai highway (UP)", "Approved by: Union Cabinet", "Ministry: Road Transport & Highways"], "source": "Moneycontrol / NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Bill to Remove Jailed Ministers After 30 Days in Custody Likely in Monsoon Session", "category": "polity", "category_name": "Polity & Governance", "summary": "The Joint Parliamentary Committee (JPC) examining the bill to disqualify Chief Ministers and ministers jailed for 30 days or more is likely to retain the key clause on removal. The JPC is expected to table its report ahead of the Monsoon Session of Parliament. The bill, if passed, would mandate automatic removal of elected officeholders held in judicial custody beyond 30 days.", "exam_angle": "Directly relevant to constitutional provisions on disqualification of legislators (Articles 102, 191), the Representation of the People Act, and separation of powers; a key polity topic for UPSC Mains.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Bill proposes: Removal of CM/ministers jailed for 30+ days", "Body examining: Joint Parliamentary Committee (JPC)", "Expected: Monsoon Session of Parliament", "Constitutional angle: Articles 102 and 191 on disqualification"], "source": "The Indian Express / The Hindu", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Centre Issues Notice to Meta, Asks WhatsApp to Halt Username Feature Over Online Fraud Concerns", "category": "polity", "category_name": "Polity & Governance", "summary": "The Central Government issued a notice to Meta asking it not to roll out WhatsApp's new username feature until consultations with the government are completed. The government expressed concerns that the feature could be exploited for online fraud and money laundering. The move reflects India's proactive regulatory approach to social media platforms under the IT Act and Digital Personal Data Protection framework.", "exam_angle": "Connects to India's IT Rules 2021, the Digital Personal Data Protection Act 2023, intermediary liability, and the government's powers to regulate social media platforms; relevant for GS Paper 2 (Governance/Polity).", "gs_paper": "GS Paper 2 (Governance)", "key_facts": ["Government body: Ministry of Electronics & IT (MeitY)", "Platform: WhatsApp (Meta)", "Concern: Online fraud and money laundering via username feature", "Regulatory framework: IT Act 2000, IT Rules 2021"], "source": "NDTV / The Hindu", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "CBI Arrests IPS Officer on Central Deputation in Rs 3 Crore Bribery Case", "category": "polity", "category_name": "Polity & Governance", "summary": "The Central Bureau of Investigation (CBI) arrested an IPS officer serving on central deputation for allegedly demanding a bribe of Rs 3 crore to 'fix' a CBI fake drugs case. A Delhi court sent the officer to custody after arrest. The case highlights issues of corruption within law enforcement and the role of CBI as an anti-corruption body.", "exam_angle": "Relevant to the role and powers of CBI, anti-corruption laws (Prevention of Corruption Act), IPS cadre rules on central deputation, and the debate on CBI's accountability.", "gs_paper": "GS Paper 2 (Governance)", "key_facts": ["Arresting agency: CBI", "Accused: IPS officer on central deputation (Haryana cadre)", "Alleged bribe: Rs 3 crore", "Purpose: To 'fix' a CBI fake drugs case"], "source": "The Hindu / The Indian Express", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Russia Purchases Gasoline from India to Tackle Domestic Fuel Shortages", "category": "ir", "category_name": "International Relations", "summary": "Russia has turned to India to buy gasoline amid a domestic fuel shortage, according to a Reuters report. Ukrainian drone attacks on Russian oil refineries have caused significant disruptions, leading Russia into a summer fuel crisis. India, which has significantly expanded its oil trade with Russia since 2022, is now emerging as a supplier of refined petroleum products to Russia as well.", "exam_angle": "Highlights the evolving India-Russia energy relationship, India's role as a major importer and now re-exporter of Russian energy, and geopolitical implications of the Ukraine conflict on global energy markets.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Russia facing fuel shortage due to Ukrainian drone strikes on refineries", "Russia is buying gasoline (refined product) from India", "India became Russia's top oil buyer after 2022 sanctions", "Source: Reuters exclusive report"], "source": "Reuters / NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Iran Asserts Control Over Strait of Hormuz, Rejects Third-Party Intervention", "category": "ir", "category_name": "International Relations", "summary": "Iran has drawn red lines over the Strait of Hormuz, rejecting any third-party intervention and insisting on maintaining control over the strategically vital waterway. Senior Iranian sources told Reuters that Tehran would not allow external interference in the strait. Separately, a ship ran aground in the Strait of Hormuz amid heightened regional tensions.", "exam_angle": "The Strait of Hormuz is one of the world's most critical oil chokepoints; Iran's control claims are significant for global energy security, India's oil imports, and the broader US-Iran geopolitical standoff.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Strait of Hormuz: ~20% of global oil trade passes through it", "Iran rejects third-party intervention in the strait", "Backdrop: US-Iran nuclear deal negotiations ongoing in Doha", "A ship ran aground in the strait amid tensions"], "source": "The Hindu / Reuters", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "US-Iran Indirect Nuclear Talks Held in Doha with Mediators; Trump Calls Meetings 'Very Good'", "category": "ir", "category_name": "International Relations", "summary": "The United States and Iran held indirect talks in Doha, Qatar, with mediators facilitating discussions on Iran's nuclear programme. US President Donald Trump described the meetings as 'very good'. The talks come amid heightened tensions following the death of Supreme Leader Ali Khamenei and uncertainty about Iran's future leadership and nuclear posture.", "exam_angle": "Iran's nuclear programme, the JCPOA framework, and US-Iran relations are perennial UPSC topics; the post-Khamenei power transition in Iran is also highly relevant for IR.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Venue: Doha, Qatar", "Format: Indirect talks via mediators", "Context: Post-Khamenei Iran and US pressure on nuclear programme", "Trump described meetings as 'very good'"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "PM Modi Dials Iranian President; India-Iran Diplomatic Engagement Continues", "category": "ir", "category_name": "International Relations", "summary": "Prime Minister Narendra Modi telephoned the Iranian President to discuss bilateral ties amid the rapidly changing geopolitical situation in Iran following Supreme Leader Khamenei's death. The call signals India's intent to maintain diplomatic continuity with Tehran. India has significant interests in Iran including the Chabahar Port project and regional connectivity via the International North-South Transport Corridor (INSTC).", "exam_angle": "India-Iran relations encompass Chabahar Port (exempted from US sanctions for India), INSTC, energy ties, and the Indian diaspora in the Gulf; this diplomatic outreach is exam-relevant.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["PM Modi called the Iranian President", "Context: Post-Khamenei leadership transition in Iran", "Key India-Iran projects: Chabahar Port, INSTC", "India balances ties with both Iran and USA/Israel"], "source": "The Indian Express", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "India Records Driest June in Over a Decade, Raising Farming Concerns", "category": "environment", "category_name": "Environment & Ecology", "summary": "India experienced its driest June in more than a decade, with rainfall significantly below the long-period average, according to BBC and IMD data. This has raised serious concerns for the agricultural sector, particularly for kharif crop sowing which depends on the southwest monsoon onset. The deficit monsoon is also expected to impact reservoir levels, water availability, and rural incomes.", "exam_angle": "Monsoon performance is directly linked to agricultural output, food inflation, rural economy, and kharif crop production; connects to IMD's role, La Niña/El Niño patterns, and GS Paper 1 (Geography) and GS Paper 3 (Agriculture/Economy).", "gs_paper": "GS Paper 1 (Geography)", "key_facts": ["India recorded its driest June in over 10 years", "Southwest monsoon is critical for kharif crop sowing", "Impact: Reservoir levels, food inflation, rural incomes", "July rainfall is considered crucial for annual agricultural output"], "source": "BBC / The Economic Times", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Assam Floods Worsen; Nearly 50,000 People Affected Across Four Districts", "category": "environment", "category_name": "Environment & Ecology", "summary": "Flood conditions in Assam worsened, with nearly 50,000 people affected across four districts. The annual Assam floods, driven by Brahmaputra river flooding, are a recurring disaster in the state. Relief and rescue operations have been deployed by the State Disaster Response Force (SDRF) and National Disaster Response Force (NDRF).", "exam_angle": "Assam floods are a recurring disaster management topic; connects to the Brahmaputra river system, NDRF, SDRF, Disaster Management Act 2005, and the broader issue of flood-prone states in India.", "gs_paper": "GS Paper 3 (Disaster Management)", "key_facts": ["Affected: ~50,000 people across 4 districts in Assam", "Cause: Annual flooding, primarily Brahmaputra river system", "Response: SDRF and NDRF deployed", "Assam is one of India's most flood-prone states"], "source": "The Times of India", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Foreign Buying of Indian Government Bonds Hits Record High After Tax Break", "category": "economy", "category_name": "Economy & Banking", "summary": "Foreign investment in Indian government bonds has reached a record high following a tax exemption introduced by the government to attract overseas capital. The development comes after India's inclusion in global bond indices such as the JP Morgan Emerging Market Bond Index. Increased foreign participation in Indian sovereign debt is expected to lower borrowing costs and deepen the domestic bond market.", "exam_angle": "India's bond market liberalisation, inclusion in global bond indices (JP Morgan, Bloomberg), FAR (Fully Accessible Route) bonds, and capital account management are key RBI/economy topics for UPSC.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Foreign buying of Indian bonds hit a record high", "Triggered by: Tax exemption on bond income for foreign investors", "India included in JP Morgan EM Bond Index (since 2024)", "Route used: Fully Accessible Route (FAR) for government securities"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Kotak Mahindra Bank to Acquire Deutsche Bank's India Retail and Wealth Business for Rs 281.7 Crore", "category": "economy", "category_name": "Economy & Banking", "summary": "Kotak Mahindra Bank has agreed to acquire Deutsche Bank's retail banking, private banking, and wealth management business in India for Rs 281.7 crore. The deal will expand Kotak's customer base and wealth management capabilities. Deutsche Bank's exit from Indian retail banking reflects its global strategy to focus on institutional and corporate businesses.", "exam_angle": "Bank mergers and acquisitions require RBI approval and are relevant to banking sector consolidation, FDI in financial services, and the role of RBI as regulator under the Banking Regulation Act.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Acquirer: Kotak Mahindra Bank", "Target: Deutsche Bank's India retail, private banking & wealth management business", "Deal value: Rs 281.7 crore", "Regulator approval required: Reserve Bank of India (RBI)"], "source": "Firstpost / The Hindu", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Finance Minister Nirmala Sitharaman on 4-Day Official Visit to France", "category": "ir", "category_name": "International Relations", "summary": "Union Finance Minister Nirmala Sitharaman embarked on an official four-day visit to France. The visit is expected to include bilateral financial discussions and meetings with French counterparts and international financial institutions. France is a key strategic partner of India and home to institutions such as the OECD, which are important in shaping global economic governance.", "exam_angle": "Ministerial visits often involve bilateral investment treaties, tax agreements, or multilateral financial discussions (OECD, FATF headquartered in Paris); relevant to India's international economic diplomacy.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Visitor: Finance Minister Nirmala Sitharaman", "Destination: France (4-day official visit)", "Source: PIB (Press Information Bureau)", "France hosts OECD and FATF headquarters — key for global financial governance"], "source": "PIB", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Gold Import Quota Licences Under India-UAE CEPA Extended to September 30, 2026", "category": "economy", "category_name": "Economy & Banking", "summary": "The government has extended the validity of FY2026 gold import quota licences under the India-UAE Comprehensive Economic Partnership Agreement (CEPA) to September 30, 2026. The extension is aimed at facilitating continued gold imports under the preferential tariff arrangement. India is the world's second-largest gold consumer, and the UAE is a major transit hub for gold imports.", "exam_angle": "India-UAE CEPA (signed March 2022, effective May 2022) was India's first FTA signed in a decade; gold import provisions and their abuse have been a policy concern; connects to trade policy, tariff concessions, and current account deficit management.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Agreement: India-UAE CEPA (Comprehensive Economic Partnership Agreement)", "Extension: Gold import quota licences valid till September 30, 2026", "India is world's 2nd largest gold consumer", "CEPA signed: February 2022; effective: May 2022"], "source": "The Economic Times", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Agnikul Cosmos Partners Finland's ICEYE for India's SAR Satellite and Launch Capability Development", "category": "scitech", "category_name": "Science & Technology", "summary": "Indian space start-up Agnikul Cosmos has partnered with Finland-based ICEYE, a leading synthetic aperture radar (SAR) satellite company, to develop SAR satellite and launch capabilities for India. Agnikul is known for its Agnibaan semi-cryogenic rocket and is one of the first private Indian launch vehicle companies. The partnership aims to build indigenous SAR satellite technology and launch services in India.", "exam_angle": "Connects to IN-SPACe (India's space regulator for private players), India's space privatisation policy post-2020, SAR satellites (used for surveillance, disaster management, agriculture), and the growing private space sector.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Partners: Agnikul Cosmos (India) and ICEYE (Finland)", "Focus: SAR (Synthetic Aperture Radar) satellite and launch capability", "Agnikul's vehicle: Agnibaan (semi-cryogenic rocket)", "Regulatory body for private space: IN-SPACe (Indian National Space Promotion and Authorisation Centre)"], "source": "Analytics India Magazine", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Ebola Outbreak in DR Congo Declared an Emergency; WHO Response Underway", "category": "environment", "category_name": "Environment & Ecology", "summary": "A new Ebola outbreak in the Democratic Republic of Congo (DRC) has been declared a public health emergency, with the World Health Organization (WHO) coordinating response efforts. Ebola virus disease (EVD) is a severe and often fatal illness in humans caused by Ebola virus. The DRC has historically been the epicentre of multiple Ebola outbreaks since the virus was first identified there in 1976.", "exam_angle": "Ebola is a recurring topic in science-tech and environment sections; WHO's role in international health emergencies (PHEIC — Public Health Emergency of International Concern), DRC's status as a biodiversity and disease hotspot, and India's preparedness protocols are exam-relevant.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Disease: Ebola Virus Disease (EVD), caused by Ebola virus (filovirus family)", "Outbreak location: Democratic Republic of Congo (DRC)", "Status: Declared a public health emergency", "First identified: 1976 in DRC (then Zaire); transmitted via direct contact with bodily fluids"], "source": "BBC", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Madras High Court Upholds Death Sentence in Child Abuse Case, Calls Crime 'More Heinous Than Murder'", "category": "polity", "category_name": "Polity & Governance", "summary": "The Madras High Court upheld a death sentence awarded in a child sexual abuse case, describing the crime as 'more heinous than murder'. The case was tried under the Protection of Children from Sexual Offences (POCSO) Act. The ruling reinforces the judiciary's stance on capital punishment in the rarest of rare cases involving crimes against children.", "exam_angle": "The POCSO Act (2012, amended 2019 to include death penalty for aggravated offences), the 'rarest of rare' doctrine (Bachan Singh v. State of Punjab, 1980), and judicial interpretation of capital punishment are important for GS Paper 2.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Court: Madras High Court", "Law applied: POCSO Act (Protection of Children from Sexual Offences Act, 2012)", "POCSO Amendment 2019: Introduced death penalty for aggravated penetrative sexual assault", "Doctrine: 'Rarest of rare' cases (Bachan Singh v. State of Punjab, 1980)"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Veteran Theatre and Film Director Vijaya Mehta Passes Away at 91", "category": "persons", "category_name": "Persons & Awards in News", "summary": "Veteran theatre and film director Vijaya Mehta passed away at the age of 91. She was a pioneering figure in Indian theatre, known for her contributions to Marathi and Hindi drama. Mehta was associated with the Indian People's Theatre Association (IPTA) tradition and received several prestigious awards for her contributions to performing arts.", "exam_angle": "Deaths of eminent personalities in arts, culture, and theatre are relevant for UPSC Current Affairs; Vijaya Mehta's association with Marathi theatre and national cultural institutions makes her a 'Persons in News' topic.", "gs_paper": "GS Paper 1 (Culture)", "key_facts": ["Vijaya Mehta: Veteran theatre and film director", "Age at death: 91", "Known for: Contributions to Marathi and Hindi theatre", "Associated with: Indian theatre's progressive tradition"], "source": "NDTV", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "Oxford Economics Report: Stricter Digital Rules May Cost India Rs 91,500 Crore in VC Funding for Startups", "category": "reports", "category_name": "Reports & Indices", "summary": "A report by Oxford Economics warns that stricter digital regulations in India could lead to a loss of Rs 91,500 crore (approximately $11 billion) in venture capital funding for startups. The report highlights concerns that overly restrictive data localisation and digital governance rules could deter foreign investment into the Indian startup ecosystem. India has one of the world's largest and fastest-growing startup ecosystems.", "exam_angle": "Connects to India's Digital Personal Data Protection Act 2023, data localisation debates, startup ecosystem, FDI in technology, and the balance between regulation and innovation — all key GS Paper 3 topics.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Report by: Oxford Economics", "Projected VC funding loss: Rs 91,500 crore (~$11 billion)", "Cause: Stricter digital rules (data localisation, DPDP Act provisions)", "India's startup ecosystem: 3rd largest globally"], "source": "The Indian Express", "day": "2026-07-01", "day_label": "01 Jul"}, {"title": "General Dhiraj Seth Takes Charge as 30th Chief of Army Staff", "category": "defence", "category_name": "Defence & Security", "summary": "General Dhiraj Seth assumed charge as the new Chief of Army Staff on June 30, 2026, succeeding General Upendra Dwivedi. The handover ceremony marked a transition in India's top military leadership. Outgoing Chief General Dwivedi noted that future wars will be more integrated and theatre-oriented in nature, signalling the direction of India's military modernisation.", "exam_angle": "Appointments to constitutional/statutory posts and senior military leadership are frequently tested in UPSC Prelims. The shift to theatre commands is a key defence reform topic for GS Paper 3.", "gs_paper": "GS Paper 3 (Defence)", "key_facts": ["New Army Chief: General Dhiraj Seth", "Outgoing Army Chief: General Upendra Dwivedi", "Effective date: June 30, 2026", "Outgoing chief's key remark: Future wars to be integrated and theatre-oriented"], "source": "The Hindu", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "India Semiconductor Mission 2.0 Gets Rs 1.25 Lakh Crore Clearance from Finance Ministry Panel", "category": "scitech", "category_name": "Science & Technology", "summary": "A Finance Ministry panel cleared a Rs 1.25 lakh crore (approximately Rs 1.25 trillion) outlay for India Semiconductor Mission 2.0, paving the way for India to deepen its semiconductor manufacturing ecosystem. The clearance signals a major policy push to reduce import dependence and position India as a global chip manufacturing hub. The original India Semiconductor Mission was launched in 2021 with a Rs 76,000 crore incentive package.", "exam_angle": "Semiconductor self-reliance is a core GS Paper 3 theme linking industrial policy, technology sovereignty, and import substitution. The scale of outlay and its approval body are key facts for Prelims.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["Scheme: India Semiconductor Mission 2.0", "Approved outlay: Rs 1.25 lakh crore", "Cleared by: Finance Ministry panel", "Objective: Advance India's semiconductor fabrication and chip design ecosystem"], "source": "NDTV Profit", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Delhi EV Policy 2026 Cleared: Focus on Two-Wheelers and Legacy Vehicle Transition", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "Delhi's Electric Vehicle Policy 2026 (EV Policy 2.0) has been officially cleared, with a significant emphasis on incentivising two-wheelers and managing the transition of legacy internal combustion engine two-wheelers and repair shops. The policy bets big on the two-wheeler segment as the primary driver of EV adoption given its dominance in Delhi's vehicle mix. It also addresses the impact on existing repair shop ecosystems during the EV transition.", "exam_angle": "State EV policies linked to national EV targets (FAME scheme, Net Zero commitments) are relevant for GS Paper 3 (Environment and Economy). Delhi's policy is particularly significant given the city's air quality challenges.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Policy: Delhi EV Policy 2026 (EV Policy 2.0)", "Key focus: Two-wheeler EV adoption and legacy vehicle transition", "Cleared by: Delhi government", "Context: Delhi's severe air pollution and national EV adoption targets"], "source": "The Indian Express", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Pakistan Threatens India Over Indus Waters Treaty as Tensions Escalate", "category": "ir", "category_name": "International Relations", "summary": "A Pakistani minister issued a strong warning to India over the Indus Waters Treaty (IWT), amid ongoing tensions following India's suspension of the treaty after the Pahalgam terror attack in April 2025. Pakistan's Indus Commissioner stated he had written to his Indian counterpart four times over fluctuations in Chenab river flows. India had placed the IWT in abeyance citing cross-border terrorism, marking one of the most significant disruptions to the 1960 treaty.", "exam_angle": "The Indus Waters Treaty (brokered by World Bank in 1960) is a perennial GS Paper 2 (IR) and GS Paper 3 topic. India's suspension and Pakistan's response connect to concepts of treaty obligations, transboundary water disputes, and diplomatic signalling.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Treaty: Indus Waters Treaty, signed 1960, brokered by World Bank", "India suspended/placed IWT in abeyance post-Pahalgam attack (April 2025)", "Rivers in dispute: Chenab (western river allocated to Pakistan)", "Pakistan's Indus Commissioner wrote 4 times to Indian counterpart over Chenab fluctuations"], "source": "Moneycontrol.com", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "US-India Trade Deal in Final Steps: US Ambassador Sergio Gor", "category": "ir", "category_name": "International Relations", "summary": "US Ambassador to India Sergio Gor stated that the bilateral trade deal between the United States and India is in its final stages, with only about 1% of negotiations remaining. Indian-American Congressman Ro Khanna simultaneously warned that the US-India relationship is at its lowest point in 30 years due to Trump administration policies. The trade deal, if concluded, would be a landmark in bilateral economic ties between the world's largest democracies.", "exam_angle": "Bilateral trade negotiations, tariff structures, and US-India economic relations are key GS Paper 2 (IR) topics. The contrast between diplomatic optimism and congressional criticism reflects the complexity of the relationship.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["US Ambassador to India: Sergio Gor", "Status: ~1% of trade deal negotiations remaining", "Ro Khanna (Indian-American Democrat): US-India ties at lowest in 30 years", "Context: Trump-era tariff disputes and bilateral trade deficit tensions"], "source": "The Hindu", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "US-Iran Nuclear Talks: Qatar Confirms No Direct Negotiations in Doha; US Envoys Meet Mediators", "category": "ir", "category_name": "International Relations", "summary": "Qatar confirmed that no direct US-Iran talks would take place in Doha, even as US special envoys Steve Witkoff and Jared Kushner met with Qatari mediators. Iranian officials engaged with Qatari intermediaries on issues including frozen funds. Qatar continues to play a key mediating role in West Asia diplomacy involving the US, Iran, and ongoing Gaza-related negotiations.", "exam_angle": "Iran nuclear diplomacy and Qatar's role as a regional mediator are important for GS Paper 2 (IR) and current geopolitical awareness. The involvement of US envoys and indirect talks format is exam-relevant.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["No direct US-Iran talks in Doha confirmed by Qatar", "US envoys: Steve Witkoff and Jared Kushner", "Qatar's role: Key intermediary/mediator in US-Iran and West Asia diplomacy", "Issues on table: Frozen Iranian funds, nuclear programme"], "source": "The Hindu", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Government Extends Import Duty Exemption on Key Petrochemical Products Till July 15", "category": "economy", "category_name": "Economy & Banking", "summary": "The Indian government extended the import duty exemption on key petrochemical products until July 15, 2026. The extension is aimed at maintaining domestic supply chain stability and keeping input costs for downstream industries in check. Petrochemicals are critical feedstocks for plastics, fertilisers, and a range of manufacturing sectors.", "exam_angle": "Import duty exemptions, trade policy, and their impact on domestic industries are GS Paper 3 topics. This connects to topics of industrial policy, custom duties, and the role of the Finance Ministry in tariff management.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Measure: Extension of import duty exemption on key petrochemical products", "Extended till: July 15, 2026", "Objective: Stabilise domestic supply chains and manage input costs", "Ministry involved: Finance Ministry (customs/tariff policy)"], "source": "Business Standard", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Finance Ministry's June Review Warns Water Scarcity May Top India's Risk Buffer List", "category": "environment", "category_name": "Environment & Ecology", "summary": "The Finance Ministry's June 2026 monthly economic review issued a new warning that water scarcity may soon top India's risk buffer list, surpassing traditional macroeconomic concerns. The report highlights the growing threat of water stress to agricultural productivity, industrial output, and overall economic resilience. This is a significant policy signal linking environmental sustainability to fiscal and economic planning.", "exam_angle": "Water scarcity as an economic and fiscal risk connects GS Paper 1 (Geography/Environment) with GS Paper 3 (Economy). Finance Ministry economic reviews are primary sources for UPSC current affairs.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Source: Finance Ministry June 2026 monthly economic review", "Warning: Water scarcity may top India's risk buffer list", "Implication: Threat to agriculture, industry, and economic resilience", "Significance: First time FinMin formally flags water as top macro risk"], "source": "Moneycontrol.com", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Europe Heatwave 2026: Record Temperatures in Slovakia and Czechia; Roads Melt", "category": "environment", "category_name": "Environment & Ecology", "summary": "A severe heatwave swept across Eastern Europe in late June 2026, with Slovakia and Czechia recording record-breaking temperatures. The World Meteorological Organization (WMO) noted the unprecedented scale of the heat event, with reports of roads melting and tram tracks buckling in affected cities. The heatwave is consistent with the broader global trend of increasing frequency and intensity of extreme heat events driven by climate change.", "exam_angle": "Extreme weather events linked to climate change, the role of the WMO, and global warming impacts are important for GS Paper 3 (Environment) and GS Paper 1 (Geography). Such events reinforce the science behind IPCC findings.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Affected region: Eastern Europe (Slovakia, Czechia worst affected)", "Authority flagging event: World Meteorological Organization (WMO)", "Impact: Record temperatures, road damage, infrastructure stress", "Context: Part of global trend of intensifying extreme heat events due to climate change"], "source": "NDTV", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Ethanol Blending Programme: Government Tells Supreme Court E20 is an Experiment, Results Expected Next Year", "category": "polity", "category_name": "Polity & Governance", "summary": "The Indian government informed the Supreme Court that the Ethanol Blending Programme (EBP), specifically the E20 target (20% ethanol blending in petrol), is being treated as an experiment and that results will be available by next year. The submission came amid concerns raised before the court about the environmental and engine-related impact of E20 fuel. India has been progressively scaling up ethanol blending as part of its energy transition and agricultural support strategy.", "exam_angle": "The Ethanol Blending Programme connects GS Paper 3 topics of energy policy, agriculture (sugarcane/maize use), environment, and judicial oversight of government schemes. Supreme Court's engagement with executive policy is also a GS Paper 2 theme.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Programme: Ethanol Blending Programme (EBP) — E20 target (20% ethanol in petrol)", "Government position before SC: E20 is an experiment; results expected in one year", "National target: 20% ethanol blending by 2025 (revised timelines under discussion)", "Significance: Connects to energy security, farmers' income, and net-zero commitments"], "source": "India Today", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "HDFC Bank Appoints Former CEC Rajiv Kumar as Chairman", "category": "persons", "category_name": "Persons & Awards in News", "summary": "HDFC Bank, India's largest private sector bank, appointed former Chief Election Commissioner (CEC) Rajiv Kumar as its new Chairman. Rajiv Kumar served as the 24th Chief Election Commissioner of India before retiring. His appointment to a top corporate board is notable given his background in civil services and election administration.", "exam_angle": "Appointments to boards of systemically important banks and the careers of former constitutional functionaries (such as the CEC) are relevant for GS Paper 2 (Polity) and Persons in News for Prelims.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Appointee: Rajiv Kumar (former Chief Election Commissioner of India)", "New role: Chairman, HDFC Bank", "HDFC Bank: India's largest private sector bank", "Rajiv Kumar was the 24th Chief Election Commissioner of India"], "source": "The Indian Express", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "Amarnath Yatra 2026: Army Deploys Anti-Drone Arsenal, Radars and Anti-Aircraft Guns for Pilgrim Security", "category": "defence", "category_name": "Defence & Security", "summary": "The Indian Army deployed a multi-layered security grid for the Amarnath Yatra 2026, including anti-drone systems, surveillance radars, and anti-aircraft guns along the pilgrimage route in Jammu & Kashmir. The J&K Lieutenant Governor performed the 'Pratham Puja' to ceremonially mark the commencement of the Yatra. The security deployment reflects heightened vigilance in the region following recent cross-border tensions.", "exam_angle": "Security arrangements for sensitive pilgrimage routes, the role of the Army in internal security, and drone threat mitigation are GS Paper 3 (Internal Security) topics. The Amarnath Yatra is also a Places in News item.", "gs_paper": "GS Paper 3 (Defence)", "key_facts": ["Event: Amarnath Yatra 2026 commencement", "Security deployed: Anti-drone systems, surveillance radars, anti-aircraft guns", "Ceremonial start: 'Pratham Puja' performed by J&K Lieutenant Governor", "Location: Jammu & Kashmir"], "source": "The Times of India", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "National Statistics Day 2026: NSO Celebrates 20th Edition in Mumbai", "category": "reports", "category_name": "Reports & Indices", "summary": "The National Statistics Office (NSO) celebrated the 20th National Statistics Day on June 29, 2026, in Mumbai. National Statistics Day is observed annually on June 29, the birth anniversary of Prof. P.C. Mahalanobis, the father of Indian statistics and founder of the Indian Statistical Institute. The day aims to promote the use of statistics in policymaking and public administration.", "exam_angle": "National Statistics Day, the NSO, and Prof. P.C. Mahalanobis are standard GS Paper 3 (Economy/Data) and Persons in News topics. The NSO is the primary government body for economic data collection and GDP estimation.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Event: 20th National Statistics Day, June 29, 2026", "Organised by: National Statistics Office (NSO)", "Day observed on: June 29 — birth anniversary of Prof. P.C. Mahalanobis", "Prof. Mahalanobis: Founder of Indian Statistical Institute (ISI), Kolkata; architect of India's statistical system"], "source": "PIB", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "RBI's New Funding Rules Impact Indian Proprietary Trading Firms", "category": "economy", "category_name": "Economy & Banking", "summary": "New funding rules issued by the Reserve Bank of India (RBI) have delivered a significant blow to Indian proprietary trading firms by restricting certain funding avenues used for leveraged trading operations. The regulations are aimed at tightening financial sector risk management and reducing systemic vulnerabilities associated with leveraged positions in capital markets. Industry stakeholders have described the impact as a 'body blow' to the prop-trading ecosystem.", "exam_angle": "RBI's regulatory role over capital markets participants, leverage restrictions, and financial sector risk management are GS Paper 3 (Economy) topics. RBI's macro-prudential regulations are frequently tested.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Regulator: Reserve Bank of India (RBI)", "Impact: New funding restrictions on proprietary trading firms", "Purpose: Reduce systemic risk from leveraged trading in capital markets", "Affected entities: Indian proprietary (prop) trading firms"], "source": "Business Standard", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "China Seen as Strategic Winner from US Military Involvement in Middle East: Report", "category": "ir", "category_name": "International Relations", "summary": "A report by The Guardian, citing strategic analysis, concluded that China is emerging as a clear geopolitical winner from the United States' military engagement in the Middle East under the Trump administration. US military focus on West Asia has diverted attention from the Indo-Pacific, allowing China to consolidate strategic and economic positions across the region. The findings have implications for India's foreign policy calculus in the Indo-Pacific.", "exam_angle": "The strategic interplay between US Middle East engagement and Indo-Pacific power dynamics is relevant for GS Paper 2 (IR). China's strategic gains amid US preoccupation is a key theme in contemporary international relations.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Finding: China is the primary strategic beneficiary of US military engagement in Middle East", "Context: Trump administration's military operations in West Asia (2026)", "Mechanism: US distraction from Indo-Pacific allows China strategic consolidation", "Implication: Shifts balance of power calculations in Indo-Pacific, relevant to India's strategic posture"], "source": "The Guardian", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "GST Completes 9 Years: Calls for Simplification, Technology Integration in Next Decade", "category": "economy", "category_name": "Economy & Banking", "summary": "As India's Goods and Services Tax (GST) entered its 9th year (implemented July 1, 2017), analysts and policymakers called for the next decade to focus on simplification of the rate structure, building taxpayer trust, and deeper technology integration. GST has transformed India's indirect tax architecture by subsuming over 17 central and state taxes. Key pending reforms include rationalisation of the rate slabs and inclusion of petroleum products under GST.", "exam_angle": "GST is a flagship constitutional amendment (101st CAA, 2016) and a core GS Paper 3 topic. Anniversary milestones, pending reforms, and the GST Council structure are standard exam themes.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["GST implemented: July 1, 2017 (9th anniversary in 2026)", "Constitutional basis: 101st Constitutional Amendment Act, 2016", "GST subsumed: 17+ central and state taxes", "Key pending reforms: Rate rationalisation, inclusion of petroleum products"], "source": "India Today NE", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "PoK Protesters Warn Pakistan Against Engaging India on Terms That Exclude PoK's Status", "category": "ir", "category_name": "International Relations", "summary": "Protesters in Pakistan-occupied Kashmir (PoK) publicly warned the Pakistani government against any diplomatic engagement with India that does not address PoK's political status, asserting that PoK is not legally part of Pakistan. The protests reflect internal dissent within PoK about Islamabad's authority over the region. This comes amid broader India-Pakistan tensions following Operation Sindoor and subsequent ceasefire.", "exam_angle": "PoK's constitutional and legal status, India's claim over the region (as part of Jammu & Kashmir per India's position), and Pakistan's internal political dynamics are important GS Paper 2 (Polity/IR) topics.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Location: Pakistan-occupied Kashmir (PoK)", "Protesters' assertion: PoK is not legally part of Pakistan", "Context: Post-Operation Sindoor India-Pakistan tensions and ceasefire", "India's position: Entire J&K (including PoK) is an integral part of India"], "source": "NDTV", "day": "2026-06-30", "day_label": "30 Jun"}, {"title": "West Bengal BJP Government to Introduce Uniform Civil Code Bill in State Assembly", "category": "polity", "category_name": "Polity & Governance", "summary": "The BJP-led West Bengal government announced plans to introduce a Uniform Civil Code (UCC) Bill in the state assembly, likely in August 2026. Opposition leader Suvendu Adhikari announced a high-powered panel to draft the legislation. West Bengal would become a significant state to attempt UCC legislation following Uttarakhand, which enacted the first state-level UCC in 2024. The move has significant constitutional and political implications given the state's demographic composition.", "exam_angle": "UCC is a Directive Principle under Article 44 of the Constitution; its state-level enactment raises questions about legislative competence and federal dynamics. Connects to GS Paper 2 topics on personal law, secularism, and centre-state relations.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Article 44 of DPSP mandates UCC for citizens throughout India", "Uttarakhand was the first state to enact a UCC law (2024)", "West Bengal BJP government announced panel; Bill likely in Assembly in August 2026", "Suvendu Adhikari (Leader of Opposition/BJP) spearheading the initiative"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Kashmir SIA Files 737-Page Chargesheet Against Yasin Malik in 1990 Sarla Bhat Murder Case", "category": "polity", "category_name": "Polity & Governance", "summary": "The State Investigation Agency (SIA) of Jammu & Kashmir filed a 737-page chargesheet naming Yasin Malik, chief of the Jammu Kashmir Liberation Front (JKLF), as the mastermind in the 1990 rape and murder of Kashmiri Pandit nurse Sarla Bhat. Four other JKLF operatives were also named in the chargesheet, filed 36 years after the incident. Yasin Malik is already serving a life sentence in Tihar Jail for terror-funding cases. The case is significant in the context of justice for Kashmiri Pandit victims of the 1990 exodus.", "exam_angle": "Connects to J&K's special status removal (Article 370), SIA's role in terror investigations, and the broader issue of justice for Kashmiri Pandits. Relevant for questions on security agencies and internal security.", "gs_paper": "GS Paper 3 (Internal Security)", "key_facts": ["SIA filed 737-page chargesheet in Sarla Bhat (1990) murder case", "Yasin Malik named as mastermind; JKLF chief currently serving life sentence for terror-funding", "Five accused named including four JKLF operatives", "Case pertains to 1990 Kashmiri Pandit exodus period"], "source": "The Indian Express", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Cabinet Approves Additional Rs 30,000 Crore Investment in National Investment and Infrastructure Fund (NIIF)", "category": "economy", "category_name": "Economy & Banking", "summary": "The Union Cabinet approved an additional investment commitment of Rs 30,000 crore in the National Investment and Infrastructure Fund (NIIF) to accelerate infrastructure investment and catalyse institutional capital into India. NIIF was established in 2015 as India's sovereign wealth fund for infrastructure. The fresh capital infusion is aimed at attracting long-term institutional investors and scaling up investment in critical infrastructure sectors.", "exam_angle": "NIIF is a key instrument for infrastructure financing in India; its structure as a sovereign wealth fund, its three-fund architecture, and its role in bridging the infrastructure financing gap are important for GS Paper 3 (Economy) and Essay papers.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Cabinet approved Rs 30,000 crore additional investment in NIIF", "NIIF established in 2015 as India's quasi-sovereign wealth fund for infrastructure", "NIIF has three funds: Master Fund, Fund of Funds, Strategic Opportunities Fund", "Objective: catalyse institutional capital and accelerate infrastructure investment"], "source": "PIB", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Delhi Cabinet Approves New EV Policy 2026 with Rs 15,000 Crore Budget", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "The Delhi Cabinet approved a new Electric Vehicle (EV) Policy 2026 with a total budget of Rs 15,000 crore. Key provisions include zero road tax on electric cars, subsidies for electric two-wheelers and autos, a mandate for only electric autos from 2027, and a phase-out of petrol two-wheelers by 2028. Hybrid vehicles will not receive subsidies under the policy. The policy aims to accelerate Delhi's transition to clean urban mobility.", "exam_angle": "Delhi EV Policy 2026 is relevant for questions on urban transport, clean energy transition, state government schemes, and India's EV ecosystem. Connects to broader National Electric Mobility Mission and FAME scheme.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["Delhi EV Policy 2026 approved with Rs 15,000 crore budget", "Zero road tax on electric cars; no subsidies for hybrid vehicles", "Only electric autos permitted from 2027; petrol two-wheelers phased out by 2028", "Policy approved by Delhi Cabinet on June 29, 2026"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Centre Lifts Wartime Petrol and Diesel Sale Restrictions from July 1, 2026", "category": "economy", "category_name": "Economy & Banking", "summary": "The Central Government announced the lifting of restrictions on the sale of petrol and diesel effective July 1, 2026, describing them as 'war-time curbs' imposed during a period of heightened security tensions. These restrictions had been put in place to manage fuel supply and prevent hoarding. The removal signals a return to normalcy in fuel retail operations across India.", "exam_angle": "Connects to India's energy security, essential commodities management, and the government's powers under the Essential Commodities Act. Relevant for questions on petroleum sector regulation and economic policy.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Centre lifts petrol/diesel sale restrictions effective July 1, 2026", "Restrictions were described as 'war-time curbs'", "Decision announced by Central Government (Ministry of Petroleum implied)", "Relevant law: Essential Commodities Act for supply-side controls"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India's Delegation to Iran for Ayatollah Khamenei's Funeral: Bihar Governor and MoS External Affairs", "category": "ir", "category_name": "International Relations", "summary": "India sent a high-level delegation to Iran for the funeral of Supreme Leader Ayatollah Ali Khamenei, comprising Bihar Governor Lt Gen Syed Ata Hasnain and Minister of State for External Affairs Pabitra Margherita. This reflects the significance India attaches to its bilateral relationship with Iran, a key partner for energy imports, the Chabahar Port project, and regional connectivity. Khamenei's death marks a major transition in Iranian politics with implications for the West Asia situation.", "exam_angle": "India-Iran relations are crucial for GS Paper 2 (IR): Chabahar Port, International North-South Transport Corridor (INSTC), energy imports, and India's strategic interests in West Asia. Leadership transition in Iran affects regional geopolitics.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India's delegation: Bihar Governor Lt Gen Syed Ata Hasnain and MoS External Affairs Pabitra Margherita", "Iran's Supreme Leader Ayatollah Ali Khamenei passed away (June 2026)", "India-Iran ties: Chabahar Port, INSTC, oil imports are key pillars", "Iran is India's third-largest oil supplier historically"], "source": "The Times of India", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India-Iran Tensions: Majority of India-Bound Ships 'Go Dark' in Strait of Hormuz", "category": "ir", "category_name": "International Relations", "summary": "Amid escalating tensions involving Iran in West Asia, a majority of India-bound cargo and oil ships were reported to have turned off their Automatic Identification System (AIS) transponders—'going dark'—while transiting the Strait of Hormuz. This is a response to the threat of Iranian interdiction. Approximately 80% of India's crude oil imports pass through the Strait of Hormuz, making disruptions a major concern for India's energy security.", "exam_angle": "The Strait of Hormuz is a critical global oil chokepoint. This event directly tests India's energy security vulnerability and connects to maritime security, freedom of navigation, and West Asia geopolitics in GS Paper 2 and 3.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Strait of Hormuz: ~20% of global oil trade passes through it", "India imports ~80% of its crude oil; majority via Strait of Hormuz", "Ships 'going dark' means turning off AIS transponders to avoid targeting", "Tensions related to US-Iran conflict and Khamenei succession"], "source": "NDTV", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "US-Iran Nuclear Talks: Disagreement Over Next Round of Negotiations in Qatar", "category": "ir", "category_name": "International Relations", "summary": "US President Trump claimed Iran had requested a fresh round of nuclear talks to be held in Qatar on Tuesday, but Iranian officials denied any such meeting was scheduled, saying no technical meeting was expected in the coming days. The contradictory statements come amid active military confrontations between US and Iran-backed forces. This follows a fragile ceasefire agreement and has significant implications for global oil prices and West Asian stability.", "exam_angle": "US-Iran nuclear negotiations, the JCPOA framework, and regional security in West Asia are standard GS Paper 2 IR topics. India as a stakeholder (oil imports, diaspora, Chabahar) makes this directly relevant.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Trump claimed Iran requested talks in Qatar; Iran denied scheduled meeting", "Context: US-Iran military clashes in West Asia (June 2026)", "Doha (Qatar) proposed as venue for nuclear talks", "JCPOA (2015 Iran nuclear deal) remains the framework reference"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Pakistan's Double-Tap Airstrikes on Afghanistan Border Kill 35, Including Children", "category": "ir", "category_name": "International Relations", "summary": "Pakistan carried out 'double-tap' airstrikes on Afghanistan's border region, killing at least 35 people including children. 'Double-tap' strikes involve a second strike shortly after the first to target first responders. The strikes escalated tensions between Pakistan and Afghanistan, with Kabul condemning the attacks. India slammed Pakistan over 'baseless' counter-claims regarding a Karachi attack, reflecting heightened India-Pakistan tensions in the broader context.", "exam_angle": "Pakistan-Afghanistan relations, cross-border terrorism, and regional security dynamics in South Asia are key GS Paper 2 IR topics. Double-tap strikes are considered a violation of international humanitarian law.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["Pakistan carried out 'double-tap' airstrikes on Afghanistan border areas", "Death toll: at least 35 including children", "India denied Pakistan's 'baseless' claims regarding a Karachi attack", "Double-tap strikes: second strike targeting first responders, considered potential war crime"], "source": "NDTV", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "US Supreme Court Blocks Trump's Bid to Fire Federal Reserve Governor; Separate Ruling Expands Presidential Powers", "category": "ir", "category_name": "International Relations", "summary": "The US Supreme Court issued two significant rulings: it blocked President Trump's attempt to fire Federal Reserve Governor Lisa Cook, upholding the central bank's independence; in a separate major ruling, the court 'supercharged' Trump's executive powers by expanding presidential authority. The Federal Reserve independence ruling is particularly relevant given ongoing concerns about political interference in monetary policy. These rulings have implications for global financial markets and governance.", "exam_angle": "Federal Reserve independence is a key concept in monetary policy. The US Supreme Court's role in checking executive overreach connects to separation of powers doctrine—a comparative constitutional law topic in GS Paper 2.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["US Supreme Court blocked Trump from firing Federal Reserve Governor Lisa Cook", "Separate ruling 'supercharged' presidential powers in executive authority case", "Federal Reserve: US central bank, founded 1913, sets monetary policy independently", "Central bank independence is a principle adopted by RBI and most major central banks"], "source": "Hindustan Times", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "CBSE Relaxes Three-Language Policy for Classes 7-9; Allows Two Foreign Language Options", "category": "schemes", "category_name": "Govt Schemes & Policies", "summary": "CBSE relaxed its three-language policy for Classes 7, 8, and 9, allowing students to opt for two foreign languages instead of being required to study a regional language as the third language. CBSE also exempted the current Class 10 batch from the three-language policy. The move drew opposition from Karnataka's state school body, which argued Kannada cannot be replaced as the third language. The policy aligns with the National Education Policy (NEP) 2020 framework but its implementation remains contested.", "exam_angle": "The three-language formula originated with the 1968 National Education Policy and is a key feature of NEP 2020. Questions on language policy, Centre-State jurisdiction over education (Concurrent List), and NEP 2020 are frequent in GS Paper 2.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["CBSE relaxed three-language policy for Classes 7, 8, 9", "Current Class 10 batch exempted from three-language policy", "Students may now opt for two foreign languages instead of mandatory regional language", "Three-language formula: part of NEP 2020; education is on the Concurrent List (Seventh Schedule)"], "source": "The Hindu", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India Seeks EU Relief on Scrap Metal Export Curbs Threatening India-EU Trade Pact Gains", "category": "ir", "category_name": "International Relations", "summary": "India sought relief from the European Union on restrictions on scrap metal exports, arguing that the curbs threaten to undermine gains from the ongoing India-EU Free Trade Agreement (FTA) negotiations. The EU's Carbon Border Adjustment Mechanism (CBAM) and export restrictions on raw materials are key points of contention. India's steel and manufacturing sectors depend significantly on scrap imports. The issue is being negotiated as part of the broader India-EU trade pact discussions.", "exam_angle": "India-EU FTA, CBAM (Carbon Border Adjustment Mechanism), and trade in raw materials are relevant for GS Paper 2 (IR) and GS Paper 3 (Economy). CBAM is also an environment-trade interface issue.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India seeking EU relief on scrap metal export restrictions", "EU's Carbon Border Adjustment Mechanism (CBAM) is a key trade concern for India", "Issue arises in context of India-EU Free Trade Agreement negotiations", "India-EU FTA talks resumed in 2022 after a decade-long pause"], "source": "Reuters", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India and Maldives Begin Week-Long Free Trade Agreement Negotiations", "category": "ir", "category_name": "International Relations", "summary": "India and the Maldives commenced a week-long round of negotiations for a bilateral Free Trade Agreement (FTA). The talks reflect India's effort to strengthen economic ties with its Indian Ocean neighbour under the 'Neighbourhood First' policy. India is the Maldives' largest trading partner and a key provider of essential commodities, tourism services, and development assistance. The FTA negotiations gain significance against the backdrop of Maldives' recent engagement with China.", "exam_angle": "India-Maldives FTA connects to India's 'Neighbourhood First' policy, SAARC, BIMSTEC, and Indian Ocean regional strategy. Relevant for GS Paper 2 (IR) questions on bilateral relations and island nations.", "gs_paper": "GS Paper 2 (IR)", "key_facts": ["India-Maldives FTA negotiations commenced (week-long round, June 2026)", "India is Maldives' largest trading partner and key development partner", "Context: India's 'Neighbourhood First' policy; Maldives' China engagement under Muizzu government", "Maldives is strategically located in the Indian Ocean: key for India's maritime security"], "source": "Firstpost", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Orissa High Court Rules Written Grounds of Arrest are Mandatory", "category": "polity", "category_name": "Polity & Governance", "summary": "The Orissa High Court ruled that providing written grounds of arrest to the arrested person is mandatory and not merely a procedural formality. The judgment reinforces the Supreme Court's earlier ruling in Pankaj Bansal v. Union of India (2023) which held that the Enforcement Directorate must supply written arrest grounds. The ruling upholds the fundamental right against arbitrary arrest under Article 22 of the Constitution.", "exam_angle": "Article 22 (Protection against arbitrary arrest) is a core fundamental right topic in GS Paper 2. The ruling connects to landmark SC judgments on arrest procedure and individual liberty.", "gs_paper": "GS Paper 2 (Polity)", "key_facts": ["Orissa High Court: written grounds of arrest are mandatory", "Article 22(1): arrested person must be informed of grounds of arrest", "SC precedent: Pankaj Bansal v. Union of India (2023) on PMLA arrest procedure", "Ruling reinforces protection of personal liberty under Articles 21 and 22"], "source": "The Times of India", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "HDFC Bank Names Former Finance Secretary Rajiv Kumar as Part-Time Chairman", "category": "persons", "category_name": "Persons & Awards in News", "summary": "HDFC Bank, India's largest private sector bank by assets, appointed former Finance Secretary Rajiv Kumar as its part-time (non-executive) Chairman. Rajiv Kumar had previously served as Finance Secretary in the Ministry of Finance and was also the 25th Chief Election Commissioner of India (2022-2023). The appointment requires RBI approval as per the Banking Regulation Act. This follows the retirement of Atanu Chakraborty as part-time chairman.", "exam_angle": "Appointments to chairmanship of major banks require RBI approval under Section 10B of the Banking Regulation Act 1949. Rajiv Kumar's prior role as CEC is noteworthy for persons-in-news questions.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Rajiv Kumar appointed Part-Time Chairman of HDFC Bank", "Previously served as Finance Secretary (MoF) and 25th Chief Election Commissioner (2022-2023)", "HDFC Bank: India's largest private sector bank", "Bank chairman appointment requires RBI approval under Banking Regulation Act 1949"], "source": "Reuters", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "India Women's Cricket Team Qualifies for 2028 Los Angeles Olympics via T20 World Cup Pathway", "category": "persons", "category_name": "Persons & Awards in News", "summary": "The Indian women's cricket team secured qualification for the 2028 Los Angeles Olympics through the T20 World Cup pathway, despite being eliminated from the current T20 World Cup by Australia. Cricket will make its Olympic debut at the LA 2028 Games. India qualified as an automatic qualifier based on ICC rankings/World Cup performance criteria. The men's team's Olympic fate is to be decided by December 2026.", "exam_angle": "Cricket's inclusion in the 2028 LA Olympics is a landmark development. Qualification criteria and the ICC-IOC agreement are relevant for questions on sports governance and India's Olympic performance.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["India women's cricket team qualifies for 2028 LA Olympics", "Cricket returns to Olympics for first time since 1900 at LA 2028", "India qualified via T20 World Cup pathway (ICC qualification system)", "Men's team Olympic qualification to be decided by December 2026"], "source": "India Today", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Harshavardhan GB Becomes India's 97th Chess Grandmaster", "category": "persons", "category_name": "Persons & Awards in News", "summary": "Harshavardhan GB achieved the title of Grandmaster in chess, becoming India's 97th Grandmaster. India has emerged as a global chess powerhouse, with the number of GMs growing rapidly. This comes in the golden era of Indian chess, with Praggnanandhaa, Gukesh (current World Champion), Arjun Erigaisi, and Vidit Gujrathi among the elite. India's chess ecosystem, supported by AICF and private academies, has propelled this growth.", "exam_angle": "India's chess dominance — including D. Gukesh becoming World Chess Champion in 2024 — is a recurring persons-in-news and sports achievement topic in current affairs.", "gs_paper": "GS Paper 1 (Culture)", "key_facts": ["Harshavardhan GB became India's 97th Chess Grandmaster", "India is the country with the most Grandmasters after Russia", "D. Gukesh is the current World Chess Champion (2024)", "FIDE GM title requires: 2500+ Elo rating and 3 GM norms"], "source": "The Times of India", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Office of Principal Scientific Adviser Launches TRL Compass Platform; Signs MoU with DSCI", "category": "scitech", "category_name": "Science & Technology", "summary": "The Office of the Principal Scientific Adviser (PSA) to the Government of India launched the Technology Readiness Level (TRL) Compass Platform and signed a Memorandum of Understanding with the Data Security Council of India (DSCI). The TRL Compass is designed to assess and map the technology maturity of Indian innovations and startups. DSCI is an industry body set up by NASSCOM focused on data protection and cybersecurity. The initiative aims to bridge the gap between research and commercialisation.", "exam_angle": "TRL (Technology Readiness Levels, a NASA-originated scale) and the role of the PSA in India's innovation ecosystem are relevant for GS Paper 3 (Sci-Tech). DSCI and data security connect to cybersecurity governance.", "gs_paper": "GS Paper 3 (Sci-Tech)", "key_facts": ["TRL Compass Platform launched by Office of Principal Scientific Adviser (PSA)", "MoU signed between PSA's office and Data Security Council of India (DSCI)", "TRL: Technology Readiness Level scale (1–9) measures maturity of technology", "DSCI: Industry body established by NASSCOM for data protection and cybersecurity"], "source": "PIB", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "European Heatwave June 2026 Breaks Records in Four Countries; Climate Attribution Shows 3.5°C Warming Effect", "category": "environment", "category_name": "Environment & Ecology", "summary": "The June 2026 European heatwave broke temperature records in four countries. Climate scientists using attribution analysis determined that a comparable heatwave in 1976 would have been 3.5°C cooler, demonstrating the direct fingerprint of anthropogenic climate change. The heatwave comes amid a broader pattern of record-breaking global temperatures in 2024–2026. Climate attribution science is now a well-established field connecting individual extreme weather events to climate change.", "exam_angle": "Climate attribution science, the link between global warming and extreme weather events, and international climate commitments (Paris Agreement 1.5°C target) are standard GS Paper 3 (Environment) topics.", "gs_paper": "GS Paper 3 (Environment)", "key_facts": ["June 2026 European heatwave broke records in four countries", "Climate attribution: heatwave would be 3.5°C cooler in pre-industrial climate (1976 baseline)", "Paris Agreement target: limit warming to 1.5°C above pre-industrial levels", "World Weather Attribution (WWA) is the leading body for extreme weather attribution studies"], "source": "The Times of India", "day": "2026-06-29", "day_label": "29 Jun"}, {"title": "Apple Accuses India's CCI of 'Copy-Pasting' Rivals' Claims in Antitrust Investigation", "category": "economy", "category_name": "Economy & Banking", "summary": "Apple Inc. accused India's Competition Commission of India (CCI) of 'copy-pasting' claims made by rivals in its ongoing antitrust investigation against the company. Apple alleged procedural unfairness in how the CCI framed its charges, claiming the investigation improperly relied on competitor submissions. The CCI investigation concerns Apple's App Store policies and the mandatory use of its in-app payment system, similar to cases in the EU and South Korea. The case is significant for India's digital market regulation.", "exam_angle": "CCI's role in regulating digital markets and Big Tech is an important GS Paper 3 (Economy) topic. The Competition Amendment Act 2023 strengthened CCI's powers, including in digital markets.", "gs_paper": "GS Paper 3 (Economy)", "key_facts": ["Apple accused CCI of 'copy-pasting' rival claims in antitrust probe", "CCI investigating Apple's App Store policies and mandatory in-app payment system", "CCI established under Competition Act 2002; strengthened by Competition Amendment Act 2023", "Similar Big Tech antitrust cases ongoing in EU (Digital Markets Act) and South Korea"], "source": "Reuters", "day": "2026-06-29", "day_label": "29 Jun"}], "categories": [{"id": "polity", "name": "Polity & Governance"}, {"id": "economy", "name": "Economy & Banking"}, {"id": "ir", "name": "International Relations"}, {"id": "environment", "name": "Environment & Ecology"}, {"id": "scitech", "name": "Science & Technology"}, {"id": "schemes", "name": "Govt Schemes & Policies"}, {"id": "defence", "name": "Defence & Security"}, {"id": "reports", "name": "Reports & Indices"}, {"id": "persons", "name": "Persons & Awards in News"}]};